  const CareCenterView = () => {
    // --- 1. INTRO / WELCOME STEP ---
    if (checkInStep === 'INTRO') {
        return (
            <div className="max-w-4xl mx-auto animate-fade-in pt-6">
                <GreetingWidget />

                <div className="max-w-2xl mx-auto text-center pt-8">
                    <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mx-auto mb-6 shadow-md border border-slate-100">
                        <CalendarCheck className="w-10 h-10 text-indigo-600" />
                    </div>
                    <h2 className="text-2xl font-bold text-slate-800 mb-4">开启今日健康打卡</h2>
                    <p className="text-slate-500 mb-8 max-w-md mx-auto">请花 2 分钟记录您的身体和心理状态，AI 将为您生成今日专属的干预方案。</p>
                    <button onClick={() => setCheckInStep('VITALS')} className="bg-indigo-600 text-white px-10 py-4 rounded-full font-bold text-lg shadow-xl shadow-indigo-200 hover:bg-indigo-700 hover:-translate-y-1 transition-all">
                        开始记录
                    </button>
                </div>
            </div>
        );
    }

    // --- 2. VITALS STEP ---
    if (checkInStep === 'VITALS') {
        return (
            <div className="max-w-xl mx-auto pt-10 animate-slide-up">
                <button onClick={() => setCheckInStep('INTRO')} className="text-slate-400 hover:text-slate-600 mb-6 flex items-center gap-1"><ArrowLeft className="w-4 h-4"/> 返回</button>
                <h2 className="text-2xl font-bold text-slate-800 mb-8">1. 基础体征记录</h2>
                <div className="space-y-6">
                    <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
                        <label className="text-sm font-bold text-slate-500 uppercase tracking-wide mb-3 block">今日体温 (℃)</label>
                        <div className="flex items-center gap-4">
                            <Thermometer className="w-8 h-8 text-blue-500" />
                            <input type="number" step="0.1" value={temp} onChange={e => setTemp(parseFloat(e.target.value))} className="w-full text-4xl font-bold text-slate-800 outline-none border-b border-slate-200 focus:border-blue-500 transition-colors py-2" />
                        </div>
                    </div>
                    <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
                        <label className="text-sm font-bold text-slate-500 uppercase tracking-wide mb-3 block">今日体重 (kg)</label>
                        <div className="flex items-center gap-4">
                            <TrendingUp className="w-8 h-8 text-emerald-500" />
                            <input type="number" step="0.1" value={weight} onChange={e => setWeight(parseFloat(e.target.value))} className="w-full text-4xl font-bold text-slate-800 outline-none border-b border-slate-200 focus:border-emerald-500 transition-colors py-2" />
                        </div>
                    </div>
                </div>
                <button onClick={() => setCheckInStep('MEDS')} className="w-full mt-8 bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                    下一步：用药打卡 <ChevronRight className="w-4 h-4" />
                </button>
            </div>
        );
    }

    // --- 2.2 MEDICATION STEP ---
    if (checkInStep === 'MEDS') {
        return (
            <div className="max-w-xl mx-auto pt-10 animate-slide-up">
                <button onClick={() => setCheckInStep('VITALS')} className="text-slate-400 hover:text-slate-600 mb-6 flex items-center gap-1"><ArrowLeft className="w-4 h-4"/> 返回</button>
                <h2 className="text-2xl font-bold text-slate-800 mb-2">2. 用药依从性记录</h2>
                <p className="text-slate-500 mb-8">按时服药是治疗成功的关键。</p>

                <div className="space-y-4">
                    <button 
                        onClick={() => setMedicationStatus('Taken')}
                        className={clsx(
                            "w-full p-6 rounded-2xl border-2 flex items-center justify-between transition-all group",
                            medicationStatus === 'Taken' ? "border-emerald-500 bg-emerald-50" : "border-slate-100 bg-white hover:border-emerald-200"
                        )}
                    >
                        <div className="flex items-center gap-4">
                            <div className={clsx("w-12 h-12 rounded-full flex items-center justify-center transition-colors", medicationStatus === 'Taken' ? "bg-emerald-500 text-white" : "bg-slate-100 text-slate-400")}>
                                <CheckCircle className="w-6 h-6" />
                            </div>
                            <div className="text-left">
                                <h3 className={clsx("font-bold text-lg", medicationStatus === 'Taken' ? "text-emerald-700" : "text-slate-700")}>我已按时服药</h3>
                                <p className="text-xs text-slate-400">遵医嘱服用今日剂量</p>
                            </div>
                        </div>
                        {medicationStatus === 'Taken' && <div className="w-4 h-4 rounded-full bg-emerald-500"></div>}
                    </button>

                    <button 
                        onClick={() => setMedicationStatus('Skipped')}
                        className={clsx(
                            "w-full p-6 rounded-2xl border-2 flex items-center justify-between transition-all group",
                            medicationStatus === 'Skipped' ? "border-red-500 bg-red-50" : "border-slate-100 bg-white hover:border-red-200"
                        )}
                    >
                        <div className="flex items-center gap-4">
                            <div className={clsx("w-12 h-12 rounded-full flex items-center justify-center transition-colors", medicationStatus === 'Skipped' ? "bg-red-500 text-white" : "bg-slate-100 text-slate-400")}>
                                <X className="w-6 h-6" />
                            </div>
                            <div className="text-left">
                                <h3 className={clsx("font-bold text-lg", medicationStatus === 'Skipped' ? "text-red-700" : "text-slate-700")}>漏服 / 未服</h3>
                                <p className="text-xs text-slate-400">忘记服用或因副作用暂停</p>
                            </div>
                        </div>
                         {medicationStatus === 'Skipped' && <div className="w-4 h-4 rounded-full bg-red-500"></div>}
                    </button>

                     <button 
                        onClick={() => setMedicationStatus('Not Required')}
                        className={clsx(
                            "w-full p-6 rounded-2xl border-2 flex items-center justify-between transition-all group",
                            medicationStatus === 'Not Required' ? "border-slate-400 bg-slate-50" : "border-slate-100 bg-white hover:border-slate-300"
                        )}
                    >
                        <div className="flex items-center gap-4">
                            <div className={clsx("w-12 h-12 rounded-full flex items-center justify-center transition-colors", medicationStatus === 'Not Required' ? "bg-slate-400 text-white" : "bg-slate-100 text-slate-400")}>
                                <PauseCircle className="w-6 h-6" />
                            </div>
                            <div className="text-left">
                                <h3 className={clsx("font-bold text-lg", medicationStatus === 'Not Required' ? "text-slate-700" : "text-slate-700")}>今日无药 / 停药期</h3>
                                <p className="text-xs text-slate-400">当前治疗阶段无需服药</p>
                            </div>
                        </div>
                        {medicationStatus === 'Not Required' && <div className="w-4 h-4 rounded-full bg-slate-400"></div>}
                    </button>
                </div>

                <button onClick={() => setCheckInStep('DT')} className="w-full mt-8 bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                    下一步：心理评估 <ChevronRight className="w-4 h-4" />
                </button>
            </div>
        );
    }

    // --- 3. DISTRESS THERMOMETER (DT) STEP ---
    if (checkInStep === 'DT') {
        return (
            <div className="max-w-xl mx-auto pt-10 animate-slide-up">
