                            <div className="text-left"><h3 className={clsx("font-bold text-lg", medicationStatus === 'Skipped' ? "text-red-700" : "text-slate-700")}>漏服 / 未服</h3><p className="text-xs text-slate-400">忘记服用或因副作用暂停</p></div>
                        </div>
                         {medicationStatus === 'Skipped' && <div className="w-4 h-4 rounded-full bg-red-500"></div>}
                    </button>
                     <button onClick={() => setMedicationStatus('Not Required')} className={clsx("w-full p-6 rounded-2xl border-2 flex items-center justify-between transition-all group", medicationStatus === 'Not Required' ? "border-slate-400 bg-slate-50" : "border-slate-100 bg-white hover:border-slate-300")}>
                        <div className="flex items-center gap-4">
                            <div className={clsx("w-12 h-12 rounded-full flex items-center justify-center transition-colors", medicationStatus === 'Not Required' ? "bg-slate-400 text-white" : "bg-slate-100 text-slate-400")}><PauseCircle className="w-6 h-6" /></div>
                            <div className="text-left"><h3 className={clsx("font-bold text-lg", medicationStatus === 'Not Required' ? "text-slate-700" : "text-slate-700")}>今日无药 / 停药期</h3><p className="text-xs text-slate-400">当前治疗阶段无需服药</p></div>
