            <div className="max-w-xl mx-auto pt-10 animate-slide-up">
                <button onClick={() => setCheckInStep('MEDS')} className="text-slate-400 hover:text-slate-600 mb-6 flex items-center gap-1"><ArrowLeft className="w-4 h-4"/> 返回</button>
