        );
    }

    if (checkInStep === 'HADS') {
        const question = HADS_QUESTIONS[currentHadsQuestion];
        const progress = ((currentHadsQuestion + 1) / HADS_QUESTIONS.length) * 100;
        return (
            <div className="max-w-xl mx-auto pt-10 animate-fade-in">
                <button onClick={() => setCheckInStep('DT')} className="text-slate-400 hover:text-slate-600 mb-6 flex items-center gap-1"><ArrowLeft className="w-4 h-4"/> 返回</button>
                <div className="mb-8">
                    <div className="flex justify-between items-end mb-2"><h2 className="text-xl font-bold text-slate-800">4. 详细心理状态评估 (HADS)</h2><span className="text-sm text-slate-400 font-mono">{currentHadsQuestion + 1} / {HADS_QUESTIONS.length}</span></div>
                    <div className="h-2 bg-slate-100 rounded-full overflow-hidden"><div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${progress}%` }} /></div>
                </div>
                <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 min-h-[300px] flex flex-col justify-center">
                    <h3 className="text-xl font-medium text-slate-800 mb-8 leading-relaxed text-center">"{question.text}"</h3>
                    <div className="space-y-3">
                        {question.options.map((opt, idx) => (
                            <button key={idx} onClick={() => handleHadsAnswer(question.scores[idx])} className="w-full p-4 rounded-xl border border-slate-100 hover:border-indigo-500 hover:bg-indigo-50 text-slate-600 hover:text-indigo-700 font-medium transition-all text-left">{opt}</button>
