                            {selectedSymptom === 'OTHER' && (
                                <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 animate-fade-in"><input type="text" placeholder="请输入症状名称" value={customSymptomText} onChange={(e) => setCustomSymptomText(e.target.value)} className="w-full bg-transparent outline-none text-slate-800 placeholder-slate-400 font-medium" autoFocus /></div>
                            )}
                            {(selectedSymptom || (selectedSymptom === 'OTHER' && customSymptomText)) && (
                                <div className="space-y-5 pt-2 border-t border-slate-100">
                                    <div className="bg-slate-50 p-5 rounded-2xl">
                                        <div className="flex justify-between text-sm mb-3"><span className="text-slate-500 font-medium flex items-center gap-2"><Zap className="w-4 h-4"/> 严重分级 (CTCAE)</span><span className={clsx("font-bold text-lg", symptomSeverity >= 3 ? "text-red-600" : "text-indigo-600")}>{symptomSeverity} 级</span></div>
                                        <input type="range" min="1" max="5" step="1" value={symptomSeverity} onChange={e => setSymptomSeverity(Number(e.target.value))} className="w-full accent-indigo-600 h-2 bg-slate-200 rounded-lg"/>
                                        <div className="flex justify-between text-[10px] text-slate-400 mt-2 mb-4"><span>轻度 (1)</span><span>中度 (2)</span><span>严重 (3)</span><span>危急 (4)</span><span>死亡 (5)</span></div>
                                        <div className={clsx("p-3 rounded-lg text-sm border transition-all animate-fade-in", symptomSeverity >= 3 ? "bg-red-50 border-red-100 text-red-800" : "bg-white border-slate-200 text-slate-600")}>
                                            <div className="flex items-start gap-2"><Info className={clsx("w-4 h-4 mt-0.5 flex-shrink-0", symptomSeverity >= 3 ? "text-red-500" : "text-slate-400")} /><div className="leading-relaxed"><span className="font-bold mr-1">定义:</span>{getCurrentGradeDescription}</div></div>
