                                })}
                                {likelySideEffects.length === 0 && <p className="text-xs text-slate-400">暂无针对该疗法的特异性预测。</p>}
                            </div>
                        </div>
                        {symptomLog.length > 0 && (
                            <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100">
                                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wide mb-3">已记录</h3>
                                <div className="space-y-2">
                                    {symptomLog.map((s, i) => (
                                        <div key={i} className="flex flex-col bg-slate-50 p-2 px-3 rounded-lg text-sm border border-slate-100">
                                            <div className="flex justify-between items-center mb-1"><span className="font-medium text-slate-700">{s.specificSymptom}</span><span className={clsx("text-xs px-1.5 py-0.5 rounded font-bold", s.severity >= 3 ? "bg-red-100 text-red-600" : s.severity >= 2 ? "bg-orange-100 text-orange-600" : "bg-green-100 text-green-600")}>{s.severity}级</span></div>
                                            {s.duration && <div className="text-[10px] text-slate-400 flex items-center gap-1"><Clock className="w-3 h-3"/> {s.duration}</div>}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                    <div className="lg:col-span-2">
                        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 p-6"><p className="text-center text-sm text-slate-400 mb-4">点击身体部位，记录详细不适（位置、强度、时间）</p><BodyMap onPartClick={handleBodyPartClick} selectedParts={symptomLog.map(l => l.bodyPart)} /></div>
                    </div>
                </div>
                <div className="fixed bottom-6 left-0 right-0 flex justify-center px-4"><button onClick={submitCheckIn} className="bg-indigo-600 text-white px-12 py-4 rounded-full font-bold text-lg shadow-xl shadow-indigo-200 hover:bg-indigo-700 hover:scale-105 transition-all">提交并生成干预方案</button></div>
            </div>
        );
    }

    // Default Result View
    return (
        <div className="max-w-4xl mx-auto pt-6 animate-fade-in pb-20">
            <GreetingWidget />
            <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 mb-8 text-center">
                 <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4 text-green-600"><CheckCircle className="w-10 h-10" /></div>
                 <h2 className="text-2xl font-bold text-slate-800 mb-2">今日打卡已完成</h2>
                 <p className="text-slate-500">AI 已为您生成今日的个性化干预建议</p>
            </div>
            <div className="space-y-6">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2"><Sparkles className="w-5 h-5 text-indigo-600" /> 智能干预方案</h3>
                {adviceList.length === 0 && (<div className="p-6 bg-slate-50 rounded-xl text-center text-slate-500">今日状态良好，暂无特别干预建议。请继续保持！</div>)}
                {adviceList.map((advice, index) => (
                    <div key={index} className={clsx("bg-white p-6 rounded-2xl shadow-sm border-l-4 transition-all hover:shadow-md", advice.severityLevel === 'Severe' ? "border-l-red-500 border-red-100" : advice.severityLevel === 'Moderate' ? "border-l-orange-500 border-orange-100" : "border-l-indigo-500 border-indigo-100")}>
                        <div className="flex justify-between items-start mb-3">
                            <div className="flex items-center gap-2"><span className={clsx("px-2 py-0.5 rounded text-xs font-bold uppercase", advice.category === 'Nutrition' ? "bg-green-100 text-green-700" : advice.category === 'Psych' ? "bg-purple-100 text-purple-700" : "bg-blue-100 text-blue-700")}>{advice.category}</span><h4 className="font-bold text-slate-800">{advice.title}</h4></div>
                            {advice.severityLevel && (<span className={clsx("text-xs font-bold px-2 py-1 rounded", advice.severityLevel === 'Severe' ? "bg-red-100 text-red-600" : advice.severityLevel === 'Moderate' ? "bg-orange-100 text-orange-600" : "bg-indigo-50 text-indigo-600")}>{advice.severityLevel}</span>)}
                        </div>
                        <p className="text-slate-600 text-sm leading-relaxed whitespace-pre-wrap mb-3">{advice.content}</p>
                        <div className="flex items-center gap-2 text-xs text-slate-400"><BrainCircuit className="w-3 h-3" /><span>来源: {advice.source}</span></div>
                    </div>
                ))}
            </div>
        </div>
    );
  };

  if (activeSection === 'medical-records') return <MedicalRecordModule />;
  return <CareCenterView />;
};

