            ].map(tab => (
                <button 
                    key={tab.id}
                    onClick={() => setRecordTab(tab.id as any)}
                    className={clsx(
                        "px-6 py-2 rounded-lg font-bold text-sm transition-all relative",
                        recordTab === tab.id ? "text-indigo-600 bg-indigo-50" : "text-slate-500 hover:bg-slate-50"
