                                        key={`ref-${m}`}
                                        y1={range.min} 
                                        y2={range.max} 
                                        fill={CHART_COLORS[i % CHART_COLORS.length]} 
                                        fillOpacity={0.05}
                                        strokeOpacity={0}
                                        ifOverflow="extendDomain"
                                    />
                                );
                            })}

