export const calculateHADSLevel = (score: number): 'Normal' | 'Mild' | 'Moderate' | 'Severe' => {
    if (score <= 7) return 'Normal';
    if (score <= 10) return 'Mild';
    if (score <= 14) return 'Moderate';
    return 'Severe';
};

