                    <div className="space-y-6">
                        {adviceList.map((advice, idx) => (
                            <div key={idx} className={clsx("bg-white p-6 rounded-2xl shadow-sm border-l-4", 
                                advice.severityLevel === 'Severe' ? "border-l-red-500" : 
                                advice.severityLevel === 'Moderate' ? "border-l-orange-500" : 
                                "border-l-indigo-500"
                            )}>
                                <div className="flex justify-between items-start mb-3">
                                    <div className="flex items-center gap-2">
                                        <span className={clsx("text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider",
                                            advice.category === 'SideEffect' ? "bg-red-50 text-red-600" :
                                            advice.category === 'Nutrition' ? "bg-green-50 text-green-600" :
                                            advice.category === 'Psych' ? "bg-purple-50 text-purple-700" :
                                            "bg-indigo-50 text-indigo-600"
                                        )}>
                                            {advice.category}
                                        </span>
                                        {advice.isComforting && <Heart className="w-4 h-4 text-pink-500 fill-pink-500" />}
                                    </div>
                                    <span className="text-xs text-slate-400">{advice.source}</span>
                                </div>
                                <h3 className="text-lg font-bold text-slate-800 mb-3">{advice.title}</h3>
                                <div className="text-sm text-slate-600 leading-relaxed whitespace-pre-wrap font-medium">
                                    {advice.content}
                                </div>
                            </div>
                        ))}
                    </div>
                    )}
            </div>
        );
    }

    return null;
  };

  if (activeSection === 'medical-records') return <MedicalRecordModule />;
  return <CareCenterView />;
};

