                                    {symptomLog.map((s, i) => (
                                        <div key={i} className="flex flex-col bg-slate-50 p-2 px-3 rounded-lg text-sm border border-slate-100">
                                            <div className="flex justify-between items-center mb-1">
                                                <span className="font-medium text-slate-700">{s.specificSymptom}</span>
                                                <span className={clsx("text-xs px-1.5 py-0.5 rounded font-bold", s.severity >= 3 ? "bg-red-100 text-red-600" : s.severity >= 2 ? "bg-orange-100 text-orange-600" : "bg-green-100 text-green-600")}>
                                                    {s.severity}级
                                                </span>
                                            </div>
                                            {s.duration && <div className="text-[10px] text-slate-400 flex items-center gap-1"><Clock className="w-3 h-3"/> {s.duration}</div>}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Right: Body Map */}
                    <div className="lg:col-span-2">
                        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 p-6">
                            <p className="text-center text-sm text-slate-400 mb-4">点击身体部位，记录详细不适（位置、强度、时间）</p>
                            <BodyMap onPartClick={handleBodyPartClick} selectedParts={symptomLog.map(l => l.bodyPart)} />
                        </div>
                    </div>
                </div>

                <div className="fixed bottom-6 left-0 right-0 flex justify-center px-4">
                    <button onClick={submitCheckIn} className="bg-indigo-600 text-white px-12 py-4 rounded-full font-bold text-lg shadow-xl shadow-indigo-200 hover:bg-indigo-700 hover:scale-105 transition-all">
                        提交并生成干预方案
                    </button>
                </div>
            </div>
        );
    }

    // --- 6. RESULT / ADVICE STEP (REVAMPED) ---
    if (checkInStep === 'RESULT') {
        // Group Advice by Category for cleaner UI
        const criticalAlerts = adviceList.filter(a => a.severityLevel === 'Severe' || a.severityLevel === 'Moderate');
        const sideEffects = adviceList.filter(a => a.category === 'SideEffect' && !criticalAlerts.includes(a));
        const nutrition = adviceList.filter(a => a.category === 'Nutrition');
        const psych = adviceList.filter(a => a.category === 'Psych' && !criticalAlerts.includes(a));

        // --- Generate "Weekly Summary" Logic ---
        const getSummaryTrend = () => {
             // Mock trend logic based on symptom count and weight
             const todaysCheckIn = patient.history.checkIns[patient.history.checkIns.length - 1];
             const symptomCount = todaysCheckIn?.symptomLog?.length || 0;
             const weightTrend = todaysCheckIn?.weight && todaysCheckIn.weight > 60 ? "稳定" : "偏低";

             let stability = "非常稳定";
             let summaryText = "过去一周您的各项指标保持平稳。";
             if (symptomCount > 2 || criticalAlerts.length > 0) {
                 stability = "有波动";
                 summaryText = `检测到 ${symptomCount} 项不适症状，建议重点关注副作用管理。`;
             }

             return { stability, weightTrend, summaryText };
        };
        const summary = getSummaryTrend();

        return (
            <div className="max-w-5xl mx-auto pt-6 animate-fade-in pb-20">
                    <GreetingWidget />
                    <div className="flex items-center justify-between mb-6">
                        <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                            <Sparkles className="w-6 h-6 text-indigo-600" /> 今日智能干预方案
                        </h2>
                        <button onClick={() => setCheckInStep('INTRO')} className="text-sm text-slate-500 hover:text-indigo-600 bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm">
                            新记录 / 重置
                        </button>
                    </div>

                    {/* --- NEW: Recent Summary Report Block --- */}
                    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 mb-8 relative overflow-hidden">
                         <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-blue-500 to-indigo-600"></div>
                         <div className="flex justify-between items-start mb-4">
                             <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                                <ClipboardCheck className="w-5 h-5 text-blue-600" /> 近期健康周报 (Weekly Brief)
                             </h3>
                             <span className="text-xs text-slate-400 bg-slate-50 px-2 py-1 rounded">AI 生成于 {new Date().toLocaleTimeString()}</span>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                             {/* Stability Metric */}
                             <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100">
                                 <div className="text-xs text-blue-500 font-bold uppercase tracking-wider mb-1">病情稳定性</div>
                                 <div className="text-xl font-bold text-slate-800 flex items-center gap-2">
                                     {summary.stability === "非常稳定" ? <CheckCircle className="w-5 h-5 text-green-500" /> : <Activity className="w-5 h-5 text-orange-500" />}
                                     {summary.stability}
                                 </div>
                             </div>
                             {/* Weight Metric */}
                             <div className="bg-emerald-50/50 p-4 rounded-xl border border-emerald-100">
                                 <div className="text-xs text-emerald-600 font-bold uppercase tracking-wider mb-1">体重趋势</div>
                                 <div className="text-xl font-bold text-slate-800 flex items-center gap-2">
                                     <Scale className="w-5 h-5 text-emerald-500" />
                                     {summary.weightTrend}
                                 </div>
                             </div>
                             {/* Summary Text */}
                             <div className="md:col-span-3 bg-slate-50 p-4 rounded-xl border border-slate-100">
                                 <p className="text-sm text-slate-600 font-medium leading-relaxed">
                                     <span className="font-bold text-slate-800">AI 综合研判：</span>
                                     {summary.summaryText} {adviceList.length === 0 ? "请继续保持良好的生活作息。" : "请根据下方方案进行调整。"}
                                 </p>
                             </div>
                         </div>
                    </div>

                    {adviceList.length === 0 ? (
                        <div className="bg-white p-12 rounded-2xl border border-slate-100 text-center shadow-sm">
                            <Smile className="w-16 h-16 text-green-500 mx-auto mb-4" />
                            <h3 className="text-xl font-bold text-slate-800 mb-2">状态极佳</h3>
                            <p className="text-slate-500">各项指标均在正常范围，请继续保持愉快心情！</p>
                        </div>
                    ) : (
                        <div className="space-y-8">
                            {/* 1. Critical Alerts (Red/Orange) */}
                            {criticalAlerts.length > 0 && (
                                <div className="space-y-4">
                                    <h3 className="text-sm font-bold text-red-600 uppercase tracking-wider flex items-center gap-2">
                                        <Siren className="w-4 h-4" /> 医疗警示 (需重视)
                                    </h3>
                                    {criticalAlerts.map((advice, idx) => (
                                        <div key={`crit-${idx}`} className="bg-white p-5 rounded-xl shadow-md border-l-4 border-l-red-500 border border-slate-100 animate-pulse-subtle">
                                            <div className="flex justify-between items-start mb-2">
                                                <h4 className="font-bold text-red-700 text-lg">{advice.title}</h4>
                                                <span className="bg-red-50 text-red-600 text-xs font-bold px-2 py-1 rounded border border-red-100">高优先级</span>
                                            </div>
                                            <p className="text-slate-700 leading-relaxed text-sm whitespace-pre-wrap">{advice.content}</p>
                                            <div className="mt-3 pt-3 border-t border-slate-50 text-xs text-slate-400 flex items-center gap-1">
                                                <ShieldCheck className="w-3 h-3" /> 来源: {advice.source}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}

                            {/* 2. Side Effects (Grid) */}
                            {sideEffects.length > 0 && (
                                <div>
                                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
                                        <ShieldCheck className="w-4 h-4 text-indigo-500" /> 副作用护理指南
                                    </h3>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        {sideEffects.map((advice, idx) => (
                                            <div key={`se-${idx}`} className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                                                <h4 className="font-bold text-slate-800 mb-2 flex items-center gap-2">
                                                    <Zap className="w-4 h-4 text-indigo-500" /> {advice.title}
                                                </h4>
                                                <p className="text-sm text-slate-600 leading-relaxed whitespace-pre-wrap">{advice.content}</p>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* 3. Nutrition & Lifestyle (Grid) */}
                            {nutrition.length > 0 && (
                                <div>
                                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
                                        <Utensils className="w-4 h-4 text-emerald-500" /> 营养支持
                                    </h3>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        {nutrition.map((advice, idx) => (
                                            <div key={`nut-${idx}`} className="bg-emerald-50/40 p-5 rounded-xl border border-emerald-100">
                                                <h4 className="font-bold text-emerald-800 mb-2 flex items-center gap-2">
                                                    <Leaf className="w-4 h-4" /> {advice.title}
                                                </h4>
                                                <p className="text-sm text-emerald-900/80 leading-relaxed whitespace-pre-wrap">{advice.content}</p>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* 4. Psychology */}
                            {psych.length > 0 && (
                                <div>
                                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
                                        <BrainCircuit className="w-4 h-4 text-purple-500" /> 心理调节
                                    </h3>
                                    <div className="bg-purple-50/40 p-5 rounded-xl border border-purple-100">
                                         {psych.map((advice, idx) => (
                                            <div key={`psy-${idx}`} className="mb-4 last:mb-0">
                                                 <h4 className="font-bold text-purple-800 mb-2 flex items-center gap-2">
                                                    <Coffee className="w-4 h-4" /> {advice.title}
                                                </h4>
                                                <p className="text-sm text-purple-900/80 leading-relaxed whitespace-pre-wrap">{advice.content}</p>
                                            </div>
                                         ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
            </div>
        );
    }

    return null;
  };

  if (activeSection === 'medical-records') return <MedicalRecordModule />;
  return <CareCenterView />;
};

