                             {/* Weight Metric */}
                             <div className="bg-emerald-50/50 p-4 rounded-xl border border-emerald-100">
                                 <div className="text-xs text-emerald-600 font-bold uppercase tracking-wider mb-1">体重趋势</div>
                                 <div className="text-xl font-bold text-slate-800 flex items-center gap-2">
                                     <Scale className="w-5 h-5 text-emerald-500" />
                                     {summary.weightTrend}
                                 </div>
                             </div>
                             {/* Summary Text */}
                             <div className="md:col-span-3 bg-slate-50 p-4 rounded-xl border border-slate-100">
                                 <p className="text-sm text-slate-600 font-medium leading-relaxed">
                                     <span className="font-bold text-slate-800">AI 综合研判：</span>
                                     {summary.summaryText} {adviceList.length === 0 ? "请继续保持良好的生活作息。" : "请根据下方方案进行调整。"}
                                 </p>
                             </div>
                         </div>
                    </div>

                    {adviceList.length === 0 ? (
                        <div className="bg-white p-12 rounded-2xl border border-slate-100 text-center shadow-sm">
                            <Smile className="w-16 h-16 text-green-500 mx-auto mb-4" />
                            <h3 className="text-xl font-bold text-slate-800 mb-2">状态极佳</h3>
                            <p className="text-slate-500">各项指标均在正常范围，请继续保持愉快心情！</p>
                        </div>
                    ) : (
                        <div className="space-y-8">
                            {/* 1. Critical Alerts (Red/Orange) */}
                            {criticalAlerts.length > 0 && (
                                <div className="space-y-4">
                                    <h3 className="text-sm font-bold text-red-600 uppercase tracking-wider flex items-center gap-2">
                                        <Siren className="w-4 h-4" /> 医疗警示 (需重视)
                                    </h3>
                                    {criticalAlerts.map((advice, idx) => (
                                        <div key={`crit-${idx}`} className="bg-white p-5 rounded-xl shadow-md border-l-4 border-l-red-500 border border-slate-100 animate-pulse-subtle">
                                            <div className="flex justify-between items-start mb-2">
                                                <h4 className="font-bold text-red-700 text-lg">{advice.title}</h4>
                                                <span className="bg-red-50 text-red-600 text-xs font-bold px-2 py-1 rounded border border-red-100">高优先级</span>
                                            </div>
                                            <p className="text-slate-700 leading-relaxed text-sm whitespace-pre-wrap">{advice.content}</p>
                                            <div className="mt-3 pt-3 border-t border-slate-50 text-xs text-slate-400 flex items-center gap-1">
                                                <ShieldCheck className="w-3 h-3" /> 来源: {advice.source}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}

                            {/* 2. Side Effects (Grid) */}
                            {sideEffects.length > 0 && (
                                <div>
                                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
                                        <ShieldCheck className="w-4 h-4 text-indigo-500" /> 副作用护理指南
                                    </h3>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        {sideEffects.map((advice, idx) => (
                                            <div key={`se-${idx}`} className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                                                <h4 className="font-bold text-slate-800 mb-2 flex items-center gap-2">
                                                    <Zap className="w-4 h-4 text-indigo-500" /> {advice.title}
                                                </h4>
                                                <p className="text-sm text-slate-600 leading-relaxed whitespace-pre-wrap">{advice.content}</p>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* 3. Nutrition & Lifestyle (Grid) */}
                            {nutrition.length > 0 && (
                                <div>
                                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
                                        <Utensils className="w-4 h-4 text-emerald-500" /> 营养支持
                                    </h3>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        {nutrition.map((advice, idx) => (
                                            <div key={`nut-${idx}`} className="bg-emerald-50/40 p-5 rounded-xl border border-emerald-100">
                                                <h4 className="font-bold text-emerald-800 mb-2 flex items-center gap-2">
                                                    <Leaf className="w-4 h-4" /> {advice.title}
                                                </h4>
                                                <p className="text-sm text-emerald-900/80 leading-relaxed whitespace-pre-wrap">{advice.content}</p>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* 4. Psychology */}
                            {psych.length > 0 && (
                                <div>
                                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
                                        <BrainCircuit className="w-4 h-4 text-purple-500" /> 心理调节
                                    </h3>
                                    <div className="bg-purple-50/40 p-5 rounded-xl border border-purple-100">
                                         {psych.map((advice, idx) => (
                                            <div key={`psy-${idx}`} className="mb-4 last:mb-0">
                                                 <h4 className="font-bold text-purple-800 mb-2 flex items-center gap-2">
                                                    <Coffee className="w-4 h-4" /> {advice.title}
                                                </h4>
                                                <p className="text-sm text-purple-900/80 leading-relaxed whitespace-pre-wrap">{advice.content}</p>
                                            </div>
                                         ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
            </div>
        );
    }

    return null;
  };

  if (activeSection === 'medical-records') return <MedicalRecordModule />;
  return <CareCenterView />;
};

export default PatientDashboard;

import React, { useState, useMemo, useEffect } from 'react';
