import { SYMPTOM_OPTIONS, generateSmartAdvice, getSideEffectsForTreatment, HADS_QUESTIONS, calculateHADSLevel, CTCAE_STANDARDS, TERM_MAPPING, GENERIC_GRADES } from '../services/knowledgeBase';
import { Heart, Activity, Thermometer, Smile, AlertCircle, Sparkles, Plus, FileText, ChevronRight, ArrowLeft, TrendingUp, CheckCircle, BrainCircuit, Pill, ShieldCheck, Zap, Info, CalendarCheck, HeartPulse, Stethoscope, Utensils, Clock, Sun, Moon, Quote, Gauge, X, PauseCircle, ArrowUp, ArrowDown, ClipboardCheck, Siren, Leaf, Coffee, Scale, PieChart, ArrowRight } from 'lucide-react';
