  // Generate UKB Profile based on ID (888 is high risk example)
  let ukbProfile: UKBLifestyleProfile | undefined;

  if (id === '888') {
    // High Risk Profile (Smoker, Poor Sleep, Low Activity)
    ukbProfile = {
      smokingStatus: 2, // Current smoker
