            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Left: Radar & Overall */}
                <div className="lg:col-span-1 bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex flex-col items-center">
                    <div className="relative w-full h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                                <PolarGrid />
                                <PolarAngleAxis dataKey="subject" tick={{ fill: '#64748b', fontSize: 12 }} />
                                <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />
                                <Radar name="健康得分" dataKey="A" stroke="#6366f1" strokeWidth={3} fill="#818cf8" fillOpacity={0.3} />
                                <Tooltip />
                            </RadarChart>
                        </ResponsiveContainer>
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                            <div className="text-3xl font-black text-indigo-600">{overallScore}</div>
                            <div className="text-[10px] text-slate-400 font-bold uppercase">综合评分</div>
                        </div>
                    </div>
                </div>

                {/* Right: Detailed Cards */}
                <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-4">
                    {/* Smoking */}
                    <div className={clsx("p-5 rounded-2xl border flex items-start gap-4", ukbProfile.smokingStatus === 2 ? "bg-red-50 border-red-100" : "bg-emerald-50 border-emerald-100")}>
                        <div className={clsx("p-3 rounded-full shrink-0", ukbProfile.smokingStatus === 2 ? "bg-red-100 text-red-600" : "bg-emerald-100 text-emerald-600")}>
                            <Cigarette className="w-6 h-6" />
                        </div>
                        <div>
                            <h4 className="font-bold text-slate-800">烟草暴露</h4>
                            <p className="text-sm text-slate-600 mt-1">
                                {ukbProfile.smokingStatus === 2 ? "当前吸烟 (高风险)" : ukbProfile.smokingStatus === 1 ? "已戒烟" : "从不吸烟"}
                            </p>
                            <p className="text-xs text-slate-400 mt-1">累积包年: {ukbProfile.packYears}年</p>
                        </div>
                    </div>

                    {/* Respiratory */}
                    <div className="bg-blue-50 p-5 rounded-2xl border border-blue-100 flex items-start gap-4">
                        <div className="p-3 bg-blue-100 rounded-full text-blue-600 shrink-0">
                            <Wind className="w-6 h-6" />
                        </div>
                        <div>
                            <h4 className="font-bold text-slate-800">呼吸功能</h4>
                            <p className="text-sm text-slate-600 mt-1">
                                气短程度: {ukbProfile.shortnessOfBreath}/4
                            </p>
                            <p className="text-xs text-slate-400 mt-1">喘鸣症状: {ukbProfile.hasWheezing ? "有" : "无"}</p>
                        </div>
                    </div>

                    {/* Sleep */}
                    <div className="bg-purple-50 p-5 rounded-2xl border border-purple-100 flex items-start gap-4">
                        <div className="p-3 bg-purple-100 rounded-full text-purple-600 shrink-0">
