                            </p>
                            <p className="text-xs text-slate-400 mt-1">主观评分: {ukbProfile.sleepQualityScore}/10</p>
                        </div>
                    </div>

                    {/* Nutrition & Activity */}
                    <div className="bg-orange-50 p-5 rounded-2xl border border-orange-100 flex items-start gap-4">
                        <div className="p-3 bg-orange-100 rounded-full text-orange-600 shrink-0">
                            <Apple className="w-6 h-6" />
                        </div>
                        <div>
                            <h4 className="font-bold text-slate-800">生活习惯</h4>
                            <p className="text-sm text-slate-600 mt-1">
                                运动: {ukbProfile.activityLevel === 0 ? "低" : "中高"} | 水果: {ukbProfile.fruitIntake}份/天
                            </p>
                            <p className="text-xs text-slate-400 mt-1">每周运动: {ukbProfile.weeklyExerciseFreq}次</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* AI Generation Section */}
            <div className="mt-8">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2">
                        <Sparkles className="w-5 h-5 text-indigo-600" /> AI 深度评估与干预建议
                    </h3>
                    {!ukbAdvice && (
                        <button 
                            onClick={handleGenerateUKBAdvice}
                            disabled={isGeneratingUKB}
                            className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all disabled:opacity-70 flex items-center gap-2"
