        <div className="bg-white rounded-3xl shadow-xl shadow-indigo-100/50 border border-slate-100 overflow-hidden relative transition-all duration-500">
            {checkInStep !== 'RESULT' && (
               <div className="absolute top-0 left-0 w-full h-1 bg-slate-100">
                   <div 
                     className="h-full bg-indigo-500 transition-all duration-500" 
                     style={{ width: `${(['INTRO','VITALS','MEDS','DT','HADS','SYMPTOMS'].indexOf(checkInStep) / 5) * 100}%` }} 
                   />
