                                />
                                <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-medium">kg</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex justify-end">
                        <button onClick={() => setCheckInStep('MEDS')} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2">
                            下一步 <ChevronRight className="w-4 h-4" />
                        </button>
                    </div>
                </div>
