            {/* MEDS STEP */}
            {checkInStep === 'MEDS' && (
                <div className="p-8">
                    <h3 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
                        <Pill className="w-6 h-6 text-indigo-500" /> 用药情况
                    </h3>
                    <p className="text-slate-500 mb-6">您是否按时服用了今日的治疗药物？</p>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
                        {[
                            { id: 'Taken', label: '已按量服用', icon: CheckCircle, color: 'bg-emerald-50 text-emerald-700 border-emerald-200' },
                            { id: 'Skipped', label: '漏服 / 忘服', icon: X, color: 'bg-red-50 text-red-700 border-red-200' },
                            { id: 'Not Required', label: '今日无需服药', icon: CalendarCheck, color: 'bg-slate-50 text-slate-700 border-slate-200' }
