                            <button
                                key={opt.id}
                                onClick={() => setMedicationStatus(opt.id as any)}
                                className={clsx(
                                    "p-4 rounded-xl border-2 flex flex-col items-center justify-center gap-3 transition-all h-32",
                                    medicationStatus === opt.id ? opt.color + " shadow-md scale-105 ring-2 ring-offset-2 ring-indigo-100" : "bg-white border-slate-100 text-slate-500 hover:bg-slate-50"
                                )}
                            >
                                <opt.icon className="w-8 h-8" />
                                <span className="font-bold">{opt.label}</span>
                            </button>
                        ))}
                    </div>
                    <div className="flex justify-between">
                        <button onClick={() => setCheckInStep('VITALS')} className="text-slate-400 font-bold hover:text-slate-600 px-4">上一步</button>
                        <button onClick={() => setCheckInStep('DT')} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2">
                            下一步 <ChevronRight className="w-4 h-4" />
                        </button>
                    </div>
                </div>
            )}

            {/* DT STEP */}
            {checkInStep === 'DT' && (
                <div className="p-8">
                    <h3 className="text-xl font-bold text-slate-800 mb-2 flex items-center gap-2">
                        <Gauge className="w-6 h-6 text-indigo-500" /> 心理痛苦温度计 (DT)
                    </h3>
                    <p className="text-slate-500 mb-8">0分代表无痛苦，10分代表极度痛苦。请评估您过去一周的平均状态。</p>

                    <div className="mb-10 px-4">
                        <div className="relative h-4 bg-gradient-to-r from-green-400 via-yellow-400 to-red-500 rounded-full mb-6">
                            <div 
                                className="absolute w-8 h-8 bg-white border-4 border-slate-800 rounded-full shadow-lg -top-2 cursor-grab active:cursor-grabbing transition-transform"
                                style={{ left: `calc(${dtScore * 10}% - 16px)` }}
                            />
                        </div>
                        <input 
                            type="range" 
                            min="0" 
                            max="10" 
                            step="1" 
                            value={dtScore} 
                            onChange={e => setDtScore(parseInt(e.target.value))}
                            className="w-full opacity-0 absolute inset-0 cursor-pointer h-12"
                        />
                        <div className="flex justify-between text-xs font-bold text-slate-400 uppercase tracking-wider">
                            <span>无痛苦 (0)</span>
                            <span>中度 (4-6)</span>
                            <span>极度痛苦 (10)</span>
                        </div>
                    </div>

                    <div className="text-center mb-8">
                        <span className={clsx(
                            "text-5xl font-black transition-colors",
                            dtScore < 4 ? "text-green-500" : dtScore < 7 ? "text-yellow-500" : "text-red-500"
                        )}>
                            {dtScore}
                        </span>
                        <p className="text-sm font-bold text-slate-500 mt-2">
                            {dtScore < 4 ? "心理状态良好" : dtScore < 7 ? "存在一定压力" : "需要专业心理支持"}
                        </p>
                    </div>

                    <div className="flex justify-between">
                        <button onClick={() => setCheckInStep('MEDS')} className="text-slate-400 font-bold hover:text-slate-600 px-4">上一步</button>
                        <button onClick={() => setCheckInStep('HADS')} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2">
                            下一步 <ChevronRight className="w-4 h-4" />
                        </button>
                    </div>
                </div>
            )}

            {/* HADS STEP */}
            {checkInStep === 'HADS' && (
                <div className="p-8">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                            <BrainCircuit className="w-6 h-6 text-indigo-500" /> 情绪评估 (HADS)
                        </h3>
                        <span className="text-xs font-bold bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full">
                            {currentHadsQuestion + 1} / {HADS_QUESTIONS.length}
                        </span>
                    </div>

                    <div className="min-h-[200px]">
                        <h4 className="text-lg font-medium text-slate-800 mb-6 leading-relaxed">
                            {HADS_QUESTIONS[currentHadsQuestion].text}
                        </h4>
                        <div className="space-y-3">
                            {HADS_QUESTIONS[currentHadsQuestion].options.map((opt, idx) => (
                                <button
                                    key={idx}
                                    onClick={() => handleHadsAnswer(HADS_QUESTIONS[currentHadsQuestion].scores[idx])}
                                    className="w-full text-left p-4 rounded-xl border border-slate-200 hover:border-indigo-500 hover:bg-indigo-50 transition-all text-slate-600 font-medium active:scale-[0.99]"
                                >
                                    {opt}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="mt-8 flex justify-between">
                         <button 
                            onClick={() => {
                                if (currentHadsQuestion > 0) setCurrentHadsQuestion(prev => prev - 1);
                                else setCheckInStep('DT');
                            }} 
                            className="text-slate-400 font-bold hover:text-slate-600 px-4"
                        >
                            上一步
                        </button>
                        {/* No next button, options trigger next */}
                    </div>
                </div>
            )}

            {/* SYMPTOMS STEP */}
            {checkInStep === 'SYMPTOMS' && (
                <div className="p-8 relative">
                    <h3 className="text-xl font-bold text-slate-800 mb-2 flex items-center gap-2">
                        <HeartPulse className="w-6 h-6 text-indigo-500" /> 症状记录
                    </h3>
                    <p className="text-slate-500 mb-6">点击身体部位添加不适症状，或下方快速选择。</p>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="bg-slate-50 rounded-2xl p-4 border border-slate-100">
                             <BodyMap 
                                onPartClick={handleBodyPartClick} 
                                selectedParts={Array.from(new Set(symptomLog.map(s => s.bodyPart)))}
                             />
                        </div>
                        <div>
                            <h4 className="font-bold text-slate-700 mb-3 text-sm uppercase tracking-wide">已记录症状</h4>
                            {symptomLog.length === 0 ? (
                                <div className="text-center py-10 border-2 border-dashed border-slate-200 rounded-xl">
                                    <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-2 text-slate-300">
                                        <Leaf className="w-6 h-6" />
                                    </div>
                                    <p className="text-slate-400 text-sm">暂无记录，身体很棒！</p>
                                </div>
                            ) : (
                                <div className="space-y-3 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                                    {symptomLog.map((log, idx) => (
                                        <div key={idx} className="bg-white p-3 rounded-xl border border-slate-100 shadow-sm flex justify-between items-center group">
                                            <div>
                                                <div className="font-bold text-slate-800">{log.specificSymptom}</div>
                                                <div className="text-xs text-slate-500 flex items-center gap-2 mt-1">
                                                    <span className="bg-slate-100 px-2 py-0.5 rounded">{log.bodyPart}</span>
                                                    <span>{log.duration}</span>
                                                    <span className={clsx(
                                                        "font-bold",
                                                        log.severity >= 3 ? "text-red-500" : "text-orange-500"
                                                    )}>{log.severity}级 - {GENERIC_GRADES[log.severity as 1|2|3|4|5]?.split(';')[0]}</span>
                                                </div>
                                            </div>
                                            <button 
                                                onClick={() => setSymptomLog(symptomLog.filter((_, i) => i !== idx))}
                                                className="text-slate-300 hover:text-red-500 p-2"
                                            >
                                                <X className="w-4 h-4" />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}

                            <div className="mt-6">
                                <h4 className="font-bold text-slate-700 mb-3 text-sm uppercase tracking-wide">常见副作用快速添加</h4>
                                <div className="flex flex-wrap gap-2">
                                    {likelySideEffects.slice(0, 5).map(eff => (
                                        <button 
                                            key={eff.name}
                                            onClick={() => toggleQuickSymptom(eff.name)}
                                            className={clsx(
                                                "px-3 py-1.5 rounded-full text-xs font-bold border transition-all",
                                                symptomLog.some(s => s.specificSymptom === eff.name) 
                                                    ? "bg-indigo-100 text-indigo-700 border-indigo-200" 
                                                    : "bg-white text-slate-600 border-slate-200 hover:border-indigo-300"
                                            )}
                                        >
                                            {eff.name}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="mt-8 flex justify-between">
                        <button onClick={() => setCheckInStep('DT')} className="text-slate-400 font-bold hover:text-slate-600 px-4">重新评估心理</button>
                        <button 
                            onClick={submitCheckIn} 
                            className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-200"
                        >
                            完成打卡并生成建议 <Sparkles className="w-5 h-5" />
                        </button>
                    </div>

                    {/* Symptom Modal Overlay */}
                    {activeBodyPart && (
                        <div className="absolute inset-0 bg-white/95 backdrop-blur-sm z-10 flex flex-col items-center justify-center p-8 animate-fade-in rounded-3xl">
                            <h4 className="text-xl font-bold text-slate-800 mb-6">选择 {activeBodyPart} 症状细节</h4>

                            <div className="w-full max-w-md space-y-6">
                                {/* Symptom Type Selection */}
                                <div className="grid grid-cols-2 gap-3">
                                    {modalSymptoms.map(sym => (
                                        <button
                                            key={sym}
                                            onClick={() => setSelectedSymptom(sym)}
                                            className={clsx(
                                                "p-3 rounded-xl border text-sm font-bold transition-all",
                                                selectedSymptom === sym ? "bg-indigo-600 text-white border-indigo-600" : "bg-white text-slate-600 border-slate-200 hover:border-indigo-300"
                                            )}
                                        >
                                            {sym}
                                        </button>
                                    ))}
                                    <button
                                        onClick={() => setSelectedSymptom('OTHER')}
                                        className={clsx(
                                            "p-3 rounded-xl border text-sm font-bold transition-all",
                                            selectedSymptom === 'OTHER' ? "bg-indigo-600 text-white border-indigo-600" : "bg-white text-slate-600 border-slate-200 hover:border-indigo-300"
                                        )}
                                    >
                                        其他 / 自定义
                                    </button>
                                </div>

                                {selectedSymptom === 'OTHER' && (
                                    <input
                                        type="text"
                                        placeholder="请输入具体症状描述..."
                                        value={customSymptomText}
                                        onChange={e => setCustomSymptomText(e.target.value)}
                                        className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
                                    />
                                )}

                                {/* Severity Slider */}
                                <div>
                                    <div className="flex justify-between mb-2">
                                        <label className="text-sm font-bold text-slate-700">严重程度 (CTCAE 分级参考)</label>
                                        <span className={clsx("text-sm font-bold", symptomSeverity>=3?"text-red-500":"text-indigo-600")}>{symptomSeverity}级</span>
                                    </div>
                                    <input 
                                        type="range" 
                                        min="1" 
                                        max="5" 
                                        value={symptomSeverity} 
                                        onChange={e => setSymptomSeverity(parseInt(e.target.value))}
                                        className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                                    />
                                    <div className="mt-2 bg-slate-50 p-3 rounded-lg text-xs text-slate-600 border border-slate-100">
                                        <span className="font-bold text-indigo-600">分级定义：</span> {getCurrentGradeDescription}
                                    </div>
                                </div>

                                {/* Duration Selection */}
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 mb-2">持续时长</label>
                                    <div className="flex flex-wrap gap-2">
                                        {DURATION_OPTIONS.map(opt => (
                                            <button
                                                key={opt}
                                                onClick={() => setSymptomDuration(opt)}
                                                className={clsx(
                                                    "px-3 py-1.5 rounded-full text-xs font-bold border transition-all",
                                                    symptomDuration === opt ? "bg-indigo-100 text-indigo-700 border-indigo-200" : "bg-white text-slate-500 border-slate-200"
                                                )}
                                            >
                                                {opt}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                <div className="flex gap-3 pt-4">
                                    <button onClick={() => setActiveBodyPart(null)} className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl">取消</button>
                                    <button 
                                        onClick={confirmSymptom} 
                                        disabled={!selectedSymptom || (selectedSymptom==='OTHER' && !customSymptomText)}
                                        className="flex-[2] bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 disabled:opacity-50 shadow-lg shadow-indigo-200"
                                    >
                                        确认添加
                                    </button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* RESULT STEP (Dashboard View) */}
            {checkInStep === 'RESULT' && (
                <div className="p-8">
                    <div className="flex items-center justify-between mb-8">
                        <div>
                            <h3 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                                <CheckCircle className="w-7 h-7 text-emerald-500" /> 今日打卡已完成
                            </h3>
                            <p className="text-slate-500 mt-1">AI 已根据您的最新状态更新了护理建议。</p>
                        </div>
                        <button 
                            onClick={() => setCheckInStep('INTRO')}
                            className="text-sm font-bold text-slate-400 hover:text-indigo-600"
                        >
                            修改记录
                        </button>
                    </div>

                    <div className="space-y-8">
                        {/* 1. Critical Alerts First */}
                        {adviceList.filter(a => a.severityLevel === 'Severe' || a.category === 'SideEffect').length > 0 && (
                            <div className="space-y-4">
                                <h4 className="font-bold text-slate-700 text-sm uppercase tracking-wide flex items-center gap-2">
                                    <AlertCircle className="w-4 h-4 text-red-500" /> 需要重点关注
                                </h4>
                                {adviceList.filter(a => a.severityLevel === 'Severe').map((advice, i) => (
                                    <div key={i} className="bg-red-50 border-l-4 border-red-500 p-4 rounded-r-xl shadow-sm">
                                        <h5 className="font-bold text-red-700 text-lg mb-2">{advice.title}</h5>
                                        <p className="text-red-900/80 text-sm whitespace-pre-wrap leading-relaxed">{advice.content}</p>
                                        <div className="mt-3 text-xs font-bold text-red-400">来源: {advice.source}</div>
                                    </div>
                                ))}
                                {/* Other Side Effects */}
                                {adviceList.filter(a => a.category === 'SideEffect' && a.severityLevel !== 'Severe').map((advice, i) => (
                                    <div key={i} className="bg-orange-50 border-l-4 border-orange-400 p-4 rounded-r-xl shadow-sm">
                                        <h5 className="font-bold text-orange-800 mb-2">{advice.title}</h5>
                                        <p className="text-orange-900/80 text-sm whitespace-pre-wrap leading-relaxed">{advice.content}</p>
                                    </div>
                                ))}
                            </div>
                        )}

                        {/* 2. Nutrition & Rehab */}
                        {adviceList.filter(a => a.category === 'Nutrition' || a.category === 'Rehab').length > 0 && (
                            <div className="space-y-4">
                                <h4 className="font-bold text-slate-700 text-sm uppercase tracking-wide flex items-center gap-2">
                                    <Utensils className="w-4 h-4 text-emerald-500" /> 饮食与康复
                                </h4>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {adviceList.filter(a => a.category === 'Nutrition' || a.category === 'Rehab').map((advice, i) => (
                                        <div key={i} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
                                            <h5 className="font-bold text-slate-800 mb-2 flex items-center gap-2">
                                                {advice.category==='Nutrition'?<Apple className="w-4 h-4 text-green-500"/>:<Activity className="w-4 h-4 text-blue-500"/>}
                                                {advice.title}
                                            </h5>
                                            <p className="text-slate-600 text-sm leading-relaxed">{advice.content}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* 3. Emotional Support */}
                        {adviceList.filter(a => a.category === 'Psych' && a.severityLevel !== 'Severe').length > 0 && (
                            <div className="bg-gradient-to-r from-indigo-50 to-purple-50 p-6 rounded-2xl border border-indigo-100">
                                <h4 className="font-bold text-indigo-800 mb-4 flex items-center gap-2">
                                    <Smile className="w-5 h-5" /> 心理加油站
                                </h4>
                                <div className="grid grid-cols-1 gap-4">
                                    {adviceList.filter(a => a.category === 'Psych' && a.severityLevel !== 'Severe').map((advice, i) => (
                                        <div key={i} className="flex gap-4 items-start">
                                            <div className="p-2 bg-white rounded-lg text-indigo-500 shadow-sm shrink-0">
                                                <Quote className="w-5 h-5" />
                                            </div>
                                            <div>
                                                <h5 className="font-bold text-indigo-900 mb-1">{advice.title}</h5>
                                                <p className="text-indigo-800/80 text-sm italic">{advice.content}</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {adviceList.length === 0 && (
                             <div className="text-center py-10 bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200">
                                 <p className="text-slate-500">今日身体状态良好，暂无特殊护理建议。继续保持！</p>
                             </div>
                        )}
                    </div>
                </div>
            )}
        </div>
      </div>
    );
  };

  if (activeSection === 'medical-records') return <MedicalRecordModule />;
  if (activeSection === 'ukb-profile') return <UKBRiskProfileView />; // New View
  return <CareCenterView />;
};

export default PatientDashboard;

