      let aScore = 0;
      let dScore = 0;
      HADS_QUESTIONS.forEach(q => {
          const score = hadsAnswers[q.id] || 0;
          if (q.category === 'A') aScore += score;
          else dScore += score;
      });
      return {
          anxietyScore: aScore,
          anxietyLevel: calculateHADSLevel(aScore),
          depressionScore: dScore,
          depressionLevel: calculateHADSLevel(dScore)
      };
  };

