                            </RadarChart>
                        </ResponsiveContainer>
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                            <div className="text-4xl font-black text-indigo-600 tracking-tight">{overallScore}</div>
