                               <p>今日状态极佳，暂无特殊护理建议。继续保持！</p>
                           </div>
                       )}
                   </div>
               </div>
           )}
        </div>
      </div>
    );
  };

  if (activeSection === 'medical-records') return <MedicalRecordModule />;
  if (activeSection === 'ukb-profile') return <UKBRiskProfileView />; // New View
  return <CareCenterView />;
};

